import { AfterViewInit, ChangeDetectionStrategy, ChangeDetectorRef, Component, DestroyRef, ElementRef, HostListener, OnInit, ViewChild, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';

// Services - teniamo solo l'essenziale
import { CreateReservationData, ReservationService } from '../../../services/Prenotazioni/reservation.service';
import { PersonalAppointment, Reservation, RestaurantClosures, Shift, Table, TaskView } from '../../../models';
import { ShiftService } from '../../../services/shift.service';
import { TableService } from '../../../services/Tavoli/table.service';
import { LucideAngularModule } from 'lucide-angular';
import { PersonalAppointmentService } from '../../../services/personal-appointment.service';
import { AuthService } from '../../../services/Base/auth.service';
