  // Calcola la capienza massima dai tavoli
  calculateMaxCapacity() {
    if (this.tables.length === 0) {
      console.log('⚠️ No tables found, using default capacity');
      this.maxCapacity = 50; // Fallback al valore fisso
      this.tableStats = null;
      return;
    }

    // Usa il metodo del servizio per calcolare
    this.maxCapacity = this.tableService.calculateMaxCapacity(this.tables);

    // Calcola statistiche
    this.tableStats = this.tableService.getTableStats(this.tables);

    console.log('📊 Capacity calculated:', {
      maxCapacity: this.maxCapacity,
      tableCount: this.tables.length,
      stats: this.tableStats
    });
  }

  // Metodo per ottenere la distribuzione delle capacità
  getCapacityDistribution(): { capacity: number, count: number }[] {
    if (!this.tables.length) return [];

    const capacityMap = this.tableService.getCapacityByTableType(this.tables);
    return Object.entries(capacityMap)
      .map(([capacity, count]) => ({
        capacity: parseInt(capacity),
        count
      }))
      .sort((a, b) => a.capacity - b.capacity);
  }

  // Metodo per ottenere tavoli disponibili per una data
  getAvailableTablesForDate(date: Date): Table[] {
    const dateStr = this.formatDateForInput(date);

    // Ottieni le prenotazioni per questa data
const dateReservations = this.events
  .filter(event => {
    const eventDateStr = this.formatDateForInput(event.start);
    return eventDateStr === dateStr && event.meta.eventType === 'reservation';
  })
  .map(event => (event.meta as ReservationMeta).reservation);

    // Tavoli prenotati per questa data
    const reservedTableIds = dateReservations
      .filter(res => res.table_id)
      .map(res => res.table_id);

    // Filtra i tavoli non prenotati
    return this.tables.filter(table =>
      !reservedTableIds.includes(table.id)
    );
  }

  // Metodo per ottenere statistiche dettagliate per una data
  getDateCapacityStats(date: Date): {
    totalCapacity: number;
    usedCapacity: number;
    availableCapacity: number;
    availableTables: number;
    percentage: number;
  } {
    const dateStr = this.formatDateForInput(date);

    // Calcola capacità utilizzata
const dateEvents = this.events.filter(event => {
  const eventDateStr = this.formatDateForInput(event.start);
  return eventDateStr === dateStr && event.meta.eventType === 'reservation';
});

const usedCapacity = dateEvents.reduce((total, event) =>
  total + ((event.meta as ReservationMeta).partySize || 0), 0
);

    // Tavoli disponibili
    const availableTables = this.getAvailableTablesForDate(date);
    const availableTablesCount = availableTables.length;

    // Capacità disponibile (dai tavoli disponibili)
    const availableCapacity = availableTables.reduce((total, table) =>
      total + (table.capacity || 0), 0
    );

    const percentage = this.maxCapacity > 0 ? (usedCapacity / this.maxCapacity) * 100 : 0;

    return {
      totalCapacity: this.maxCapacity,
      usedCapacity,
      availableCapacity,
      availableTables: availableTablesCount,
      percentage: Math.round(percentage)
    };
  }

